import{_ as n,C as o,o as s,c as l,E as i,w as t,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Ireland Legal Rights","description":"Legal rights for transgender people in Ireland","frontmatter":{"layout":"doc","title":"Ireland Legal Rights","description":"Legal rights for transgender people in Ireland"},"headers":[],"relativePath":"europe/ireland/legal-rights.md","filePath":"europe/ireland/legal-rights.md","lastUpdated":null}'),c={name:"europe/ireland/legal-rights.md"};function g(h,e,p,u,m,f){const a=o("Badge");return s(),l("div",null,[i(a,{variant:"yellow"},{default:t(()=>[...e[0]||(e[0]=[r("Self-ID since 2015",-1)])]),_:1}),i(a,{variant:"green"},{default:t(()=>[...e[1]||(e[1]=[r("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-ireland" tabindex="-1">Legal Rights in Ireland <a class="header-anchor" href="#legal-rights-in-ireland" aria-label="Permalink to &quot;Legal Rights in Ireland&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Ireland passed the Gender Recognition Act in 2015, allowing self-declaration of gender for adults. Applicants must be 18 or over and submit a statutory declaration to the Department of Social Protection stating their gender identity. No medical diagnosis, surgery, hormone therapy, or sterilisation is required.</p><p>A Gender Recognition Certificate is issued within a few weeks. For minors aged 16-17, a court order is required. For those under 16, a court order plus parental consent is needed.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Ireland does not have a formal name change process — you can simply begin using a new name. Most organisations (banks, employers, utility companies) accept a statutory declaration or deed poll. The Gender Recognition Certificate itself serves as strong evidence for updating documents.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>The Employment Equality Acts and Equal Status Acts prohibit discrimination based on gender in:</p><ul><li><strong>Employment</strong>: All areas of employment</li><li><strong>Goods and services</strong>: Housing, healthcare, education</li><li><strong>Public services</strong>: Access to public facilities</li></ul><p>While gender identity is not explicitly listed, the Irish Human Rights and Equality Commission (IHREC) interprets &quot;gender&quot; to include transgender people.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>The Criminal Justice (Hate Crime) Act 2024 explicitly includes gender identity and gender expression as protected characteristics. Transphobic motivation is an aggravating factor in sentencing. An Garda Síochána (Irish police) has dedicated diversity officers.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://teni.ie/" target="_blank" rel="noreferrer">TENI - Transgender Equality Network Ireland</a> — Advocacy and legal guidance</li><li><a href="https://www.ihrec.ie/" target="_blank" rel="noreferrer">IHREC</a> — Human rights and equality complaints</li><li><a href="https://www.gov.ie/en/campaigns/40f4a5-gender-recognition/" target="_blank" rel="noreferrer">Department of Social Protection</a> — Gender Recognition Certificates</li></ul>',14))])}const _=n(c,[["render",g]]);export{y as __pageData,_ as default};
